const d = $input.first().json;
const emoji = {
  LANDING: '🌐',
  INSTAGRAM: '📸',
  FACEBOOK: '👤',
  WHATSAPP: '💬',
  GOOGLE: '🔍',
  REFERIDO: '🤝',
  OTRO: '📌',
};
const src = emoji[d.source] ?? '📌';
const campaign = d.campaign ? `\n📁 Campaña: ${d.campaign}` : '';
const utm = d.utmSource && d.utmSource !== 'directo' ? `\n🔗 UTM: ${d.utmSource}` : '';

const msg = [
  '🩺 *Nuevo Lead — Sara Medical*',
  '',
  `👤 *Nombre:* ${d.name}`,
  d.phone    ? `📞 *Teléfono:* ${d.phone}`    : null,
  d.email    ? `📧 *Email:* ${d.email}`        : null,
  d.specialty? `🏥 *Especialidad:* ${d.specialty}` : null,
  d.city     ? `📍 *Ciudad:* ${d.city}`        : null,
  `${src} *Fuente:* ${d.source}${campaign}${utm}`,
  `🕐 *Fecha:* ${d.date ?? new Date().toLocaleString('es-EC', { timeZone: 'America/Guayaquil' })}`,
  '',
  '💡 _Responde pronto para aumentar la tasa de conversión._',
].filter(Boolean).join('\n');

return [{ json: { message: msg, phone: '593996691586' } }];
